function accountSort(a,b){return a.code.localeCompare(b.code,'en',{numeric:true})}
function leaf(code,names,type,nature){return{code,names,type,nature}}
function defaultAccounts(){let leaves=[leaf('1-01-01-001-001-001',['الأصول','الأصول المتداولة','النقدية والبنوك','الصندوق','صناديق التشغيل','الصندوق الرئيسي'],'أصل','مدين'),leaf('1-01-01-002-001-001',['الأصول','الأصول المتداولة','النقدية والبنوك','البنوك','الحسابات البنكية','الحساب البنكي'],'أصل','مدين'),leaf('1-01-02-001-001-001',['الأصول','الأصول المتداولة','الذمم المدينة','العملاء','عملاء النشاط','العملاء'],'أصل','مدين'),leaf('1-01-03-001-001-001',['الأصول','الأصول المتداولة','المخزون','الأعلاف','أعلاف','مخزون أعلاف'],'أصل','مدين'),leaf('1-01-03-002-001-001',['الأصول','الأصول المتداولة','المخزون','الصيصان','صيصان','مخزون صيصان'],'أصل','مدين'),leaf('1-01-03-003-001-001',['الأصول','الأصول المتداولة','المخزون','أدوية ولقاحات','أدوية','مخزون أدوية ولقاحات'],'أصل','مدين'),leaf('1-01-06-001-001-001',['الأصول','الأصول المتداولة','الضريبة','ضريبة القيمة المضافة','ضريبة مدخلات','ضريبة القيمة المضافة مدخلات'],'أصل','مدين'),leaf('1-02-01-001-001-001',['الأصول','الأصول غير المتداولة','ممتلكات ومعدات','عنابر ومزارع','عنابر','عنابر دجاج'],'أصل','مدين'),leaf('1-02-02-001-001-001',['الأصول','الأصول غير المتداولة','ممتلكات ومعدات','معدات','معدات تشغيل','معدات مزارع'],'أصل','مدين'),leaf('2-01-01-001-001-001',['الالتزامات','التزامات متداولة','الذمم الدائنة','الموردون','موردون عامون','الموردون'],'التزام','دائن'),leaf('2-01-02-001-001-001',['الالتزامات','التزامات متداولة','مصروفات مستحقة','رواتب مستحقة','رواتب','رواتب مستحقة الدفع'],'التزام','دائن'),leaf('2-01-03-001-001-001',['الالتزامات','التزامات متداولة','الضريبة','ضريبة القيمة المضافة','ضريبة مخرجات','ضريبة القيمة المضافة مخرجات'],'التزام','دائن'),leaf('3-01-01-001-001-001',['حقوق الملكية','رأس المال','رأس مال المالك','رأس مال','رأس مال مدفوع','رأس المال'],'حقوق ملكية','دائن'),leaf('3-01-02-001-001-001',['حقوق الملكية','جاري المالك','جاري المالك','عمليات المالك','حساب جاري','جاري المالك'],'حقوق ملكية','دائن'),leaf('4-01-01-001-001-001',['الإيرادات','إيرادات النشاط','مبيعات','مبيعات دواجن','مبيعات دجاج لاحم','مبيعات الدواجن'],'إيراد','دائن'),leaf('4-02-01-001-001-001',['الإيرادات','إيرادات أخرى','إيرادات فرعية','مخلفات وفرشة','مبيعات سماد','إيراد بيع سماد وفرشة'],'إيراد','دائن'),leaf('5-01-01-001-001-001',['تكلفة المبيعات','تكاليف مباشرة','الصيصان','صيصان عمر يوم','تكلفة صيصان','تكلفة صيصان مستهلكة'],'مصروف','مدين'),leaf('5-01-01-002-001-001',['تكلفة المبيعات','تكاليف مباشرة','الأعلاف','علف','تكلفة علف','تكلفة أعلاف مستهلكة'],'مصروف','مدين'),leaf('5-03-01-001-001-001',['تكلفة المبيعات','المشتريات','مشتريات نشاط','مشتريات عامة','مشتريات قابلة للتحميل','المشتريات العامة'],'مصروف','مدين'),leaf('6-01-01-001-001-001',['المصروفات التشغيلية','مصروفات إدارية','رواتب وأجور','رواتب','رواتب موظفين','مصروف الرواتب والأجور'],'مصروف','مدين'),leaf('6-03-01-001-001-001',['المصروفات التشغيلية','مصروفات تمويلية','رسوم بنكية','عمولات','رسوم تحويل','رسوم وعمولات بنكية'],'مصروف','مدين')];let m=new Map();for(let l of leaves){let p=l.code.split('-');for(let i=1;i<=p.length;i++){let c=p.slice(0,i).join('-');if(!m.has(c))m.set(c,{code:c,name:l.names[i-1]||l.names.at(-1),type:l.type,nature:l.nature,level:i,parent:i>1?p.slice(0,i-1).join('-'):'',posting:false,active:true,notes:''});}let a=m.get(l.code);a.name=l.names[5];a.posting=true;}return[...m.values()].sort(accountSort)}
function blank(){return{settings:{sellerName:ORG,sellerVat:'',sellerCR:'',sellerAddress:'',bankName:''},accounts:defaultAccounts(),parties:[],entries:[],invoices:[],vouchers:[],payroll:[],seq:{entry:1,doc:1,party:1,voucher:1,payroll:1}}}
function load(){try{return JSON.parse(localStorage.getItem(KEY))||blank()}catch(e){return blank()}}
function save(){localStorage.setItem(KEY,JSON.stringify(S))}function toast(t){toastEl=$('toast');toastEl.textContent=t;toastEl.classList.add('show');clearTimeout(window._t);window._t=setTimeout(()=>toastEl.classList.remove('show'),2300)}
function enterApp(){cover.classList.add('hidden');app.classList.remove('hidden');renderAll()}document.querySelectorAll('.nav button').forEach(b=>b.onclick=()=>show(b.dataset.page));function show(p){document.querySelectorAll('.page').forEach(x=>x.classList.remove('active'));$(p).classList.add('active');document.querySelectorAll('.nav button').forEach(b=>b.classList.toggle('active',b.dataset.page===p));nav.classList.remove('open');renderAll()}
function acc(c){return S.accounts.find(a=>a.code===c)}function accName(c){return acc(c)?.name||''}function postable(){return S.accounts.filter(a=>a.active&&a.posting).sort(accountSort)}function resolveAccount(v){let q=norm(v);let a=S.accounts.find(x=>norm(x.code)===q)||S.accounts.find(x=>norm(`${x.code} - ${x.name}`)===q)||S.accounts.find(x=>norm(x.name)===q)||S.accounts.find(x=>norm(x.code+' '+x.name).includes(q));return a?.code||v}function dateIn(d,f,t){return(!f||d>=f)&&(!t||d<=t)}function activeEntries(){return S.entries.filter(e=>e.status==='نشط')}function allLines(){return activeEntries().flatMap(e=>(e.lines||[]).map(l=>({...l,entryId:e.id,date:e.date,title:e.title,desc:e.desc,source:e.source||''})))}function next(k){return S.seq[k]||1}function bump(k,id){S.seq[k]=Math.max(next(k),Number(id)+1)}
