function vatTotals(){let out=0,inn=0;for(let d of S.invoices){let sign=d.docClass==='credit'?-1:1;if(d.type==='sale')out+=sign*n(d.totals.vat);else inn+=sign*n(d.totals.vat)}return{out:n(out),in:n(inn),net:n(out-inn)}}function taxExport(){let v=vatTotals(),b=balancesByType(),profit=financialExport().find(x=>x['البند']==='صافي الربح/الخسارة')?.['المبلغ']||0;let base=n((-(b['حقوق ملكية']||0))+Math.max(profit,0)+n(zakatAdj?.value)-((b['أصل']||0)*0.35));let zakat=Math.max(0,n(base*.025));return[{'التقرير':'ضريبة القيمة المضافة','البند':'ضريبة المخرجات','المبلغ':v.out},{'التقرير':'ضريبة القيمة المضافة','البند':'ضريبة المدخلات','المبلغ':v.in},{'التقرير':'ضريبة القيمة المضافة','البند':'صافي الضريبة المستحقة','المبلغ':v.net},{'التقرير':'الزكاة التقديرية','البند':'الوعاء الزكوي التقريبي','المبلغ':base},{'التقرير':'الزكاة التقديرية','البند':'الزكاة 2.5%','المبلغ':zakat}]}function renderTaxReports(){if(!taxBox)return;taxBox.innerHTML='<div class="summary">احتساب الزكاة هنا تقديري ومحاسبي داخلي، وليس إقرارًا رسميًا.</div><div class="tablewrap"><table>'+tableFromRows(taxExport()).replace(/^<table>|<\/table>$/g,'')+'</table></div>'}
